class Solution:
    def findAnswer(self, parent, s):
        n = len(parent)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parent[i]].append(i)
        for c in children:
            c.sort()
        result = [False] * n
        for i in range(n):
            buf = []

            def dfs(x):
                for y in children[x]:
                    dfs(y)
                buf.append(s[x])

            dfs(i)
            st = ''.join(buf)
            result[i] = st == st[::-1]
        return result

