var findAnswer = function(parent, s) {
    const n = parent.length;
    const children = Array.from({ length: n }, () => []);
    for (let i = 1; i < n; i++) children[parent[i]].push(i);
    for (const c of children) c.sort((a, b) => a - b);
    const pre = [];
    const stack = [0];
    while (stack.length) {
        const node = stack.pop();
        pre.push(node);
        for (const ch of children[node]) stack.push(ch);
    }
    const order = pre.slice().reverse();
    const pos = new Array(n).fill(0);
    order.forEach((node, idx) => { pos[node] = idx; });
    const size = new Array(n).fill(1);
    for (const node of order) {
        if (node !== 0) size[parent[node]] += size[node];
    }
    let text = '';
    for (const node of order) text += s[node];
    const answer = new Array(n).fill(false);
    for (let node = 0; node < n; node++) {
        const r = pos[node];
        const l = r - size[node] + 1;
        const seg = text.slice(l, r + 1);
        let ok = true;
        for (let a = 0, b = seg.length - 1; a < b; a++, b--) {
            if (seg[a] !== seg[b]) { ok = false; break; }
        }
        answer[node] = ok;
    }
    return answer;
};
